package com.parkflow.mall.gateway.controller;
import com.parkflow.mall.gateway.vision.VisionServiceProxy;import java.io.IOException;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;
@RestController public class VisionGatewayController {private final VisionServiceProxy proxy;public VisionGatewayController(VisionServiceProxy proxy){this.proxy=proxy;}@PostMapping(value="/api/vision/ocr/plate",consumes="multipart/form-data")public ResponseEntity<String> ocr(@RequestHeader(value="Authorization",required=false)String authorization,@RequestPart(value="image",required=false)MultipartFile image,@RequestParam(required=false)String cameraId,@RequestParam(required=false)String gateId)throws IOException{if(image==null)return ResponseEntity.badRequest().body("{\"detail\":\"image is required\"}");return proxy.ocr(authorization,image,cameraId,gateId);}}
